// // This module gates the clock signal based on the enable and test enable signals.
// It outputs the clock signal only when both enable and test enable are low.

module clock_gate (
    input clk,
    input en,
    input te,
    output reg en_clk
);

always @(*) begin
    if (en && te) begin
        en_clk = clk;
    end
    else begin
        en_clk = 1'b0;
    end
end

endmodule
